4	describe("Game of Life - Next Generation", () => {
5	  it("should return empty board for empty input", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should return empty board for single living cell (dies from underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should keep two adjacent cells alive if they form a stable pair", () => {
12	    expect(nextGeneration([[0, 0], [0, 1]])).toEqual([[0, 0], [0, 1]]);
13	  });
14	  it("should eliminate overpopulated cell with 4 neighbors", () => {
15	    // A cell at [0, 0] with 4 neighbors should die from overpopulation
16	    expect(nextGeneration([[0, 0], [0, 1], [1, 0], [1, 1], [-1, 0]])).toEqual([[0, 1], [1, 0], [1, 1], [-1, 0]]);
17	  });
18	  it("should create new cell from reproduction (dead cell with exactly 3 neighbors)", () => {
19	    // Three cells arranged so [0, 1] (empty) has exactly 3 neighbors: [0, 0], [1, 0], [1, 1]
20	    expect(nextGeneration([[0, 0], [1, 0], [1, 1]])).toEqual([[0, 0], [1, 0], [1, 1], [0, 1]]);
21	  });
