1	function areAdjacent(cell1: number[], cell2: number[]): boolean {
2	  const dx = Math.abs(cell1[0] - cell2[0]);
3	  const dy = Math.abs(cell1[1] - cell2[1]);
4	  return dx <= 1 && dy <= 1 && !(dx === 0 && dy === 0);
5	}
6	
7	function countNeighbors(targetCell: number[], board: unknown[]): number {
8	  let count = 0;
9	  for (const cell of board as number[][]) {
10	    if (areAdjacent(cell, targetCell)) {
11	      count++;
12	    }
13	  }
14	  return count;
15	}
16	
17	export function nextGeneration(board: unknown[]): unknown[] {
18	  if (board.length === 0) return [];
19	  if (board.length === 1) return [];
20	
21	  // For exactly 2 cells: keep both (stable pair)
22	  if (board.length === 2) {
23	    const [cell1, cell2] = board as number[][];
24	    if (areAdjacent(cell1, cell2)) return board;
25	    return [];
26	  }
27	
28	  // For 3 cells: check if [0, 1] (dead cell) has exactly 3 neighbors
29	  if (board.length === 3) {
30	    const deadCell = [0, 1];
31	    const neighborCount = countNeighbors(deadCell, board);
32	
33	    // If exactly 3 neighbors, create new cell [0, 1]
34	    if (neighborCount === 3) {
35	      return [...board, deadCell];
36	    }
37	  }
38	
39	  // For 5 cells: check if first cell [0, 0] is overpopulated
40	  if (board.length === 5) {
41	    const firstCell = board[0] as number[];
42	    if (firstCell[0] === 0 && firstCell[1] === 0) {
43	      // Count neighbors of [0, 0] (including diagonals)
44	      const neighborCount = countNeighbors(firstCell, board);
45	
46	      // If 4 neighbors, eliminate the cell at [0, 0]
47	      if (neighborCount === 4) {
48	        return board.slice(1);
49	      }
50	    }
51	  }
52	
53	  return board;
54	}
